  ('dietitian-moex-06949', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於「糧食安全」概念架構中，「食物攝取」和「健康狀況」的直接原因，下列敘述何者錯誤？ 「照護能量」為「食物攝取」的直接原因  「衛生服務」為「健康狀況」的直接原因 「環境狀況」為「健康狀況」的直接原因  「環境狀況」為「食物攝取」的直接原因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06950', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於「公共衛生營養」的敘述，下列何者錯誤？ 工作範圍包括設計社區營養問題之計畫 包括與社區健康有關之食物及營養問題 是藉著個人力量有效的解決個人的營養問題 工作範圍包括建立社區中食品及營養政策、組織與管理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06951', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '林教授設計了一份飲食頻率問卷。經測試後發現，該問卷在評估個人每日維生素B 攝取量時，和血液PLP 6 濃度相關係數為 0.5，但若重複利用此問卷測量同一個人時，則發現前後兩次 B 之攝取量相差約 10%。 6 此種情形表示此問卷之測量能力如何？ 信度低、效度低  信度低、效度高  信度高、效度低  信度高、效度高', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
